import React, { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import "../styles/AllNews.css";
import NewsCard from "./NewsCard"; // Import the new NewsCard component
import ReadMore from "./ReadMore";  // Import ReadMore component

const articles = [
    {
      id: 1,
      title:
        "LENIENCY IN CRIMINAL SENTENCE FOR JUSTICE COLLABORATORS WHO SUPPORT LAW ENFORCEMENT AUTHORITIES BY UNCOVERING CRIMINAL CASES",
      date: "06 February, 2025",
      image: "/images/news1.jpg",
      description:
        "The key to a successful criminal law enforcement depends on the evidence that has been...",
      fullText:
        "Full article content goes here. This is the detailed explanation...",
    },
    {
      id: 2,
      title:
        "PROTECTION OF OPEN-SOURCE SOFTWARE FROM A COPYRIGHT PERSPECTIVE IN INDONESIA",
      date: "06 February, 2025",
      image: "/images/news2.jpg",
      description:
        "How is open source regulated in copyright law in Indonesia? Despite its nature...",
      fullText:
        "Full article content goes here. This is the detailed explanation...",
    },
    {
      id: 3,
      title:
        "PROTECTION OF OPEN-SOURCE SOFTWARE FROM A COPYRIGHT PERSPECTIVE IN INDONESIA",
      date: "06 February, 2025",
      image: "/images/news3.jpg",
      description:
        "How is open source regulated in copyright law in Indonesia? Despite its nature...",
      fullText:
        "Full article content goes here. This is the detailed explanation...",
    },
    {
        id: 4,
        title:
          "LENIENCY IN CRIMINAL SENTENCE FOR JUSTICE COLLABORATORS WHO SUPPORT LAW ENFORCEMENT AUTHORITIES BY UNCOVERING CRIMINAL CASES",
        date: "06 February, 2025",
        image: "/images/news1.jpg",
        description:
          "The key to a successful criminal law enforcement depends on the evidence that has been...",
        fullText:
          "Full article content goes here. This is the detailed explanation...",
      },
      {
        id: 5,
        title:
          "PROTECTION OF OPEN-SOURCE SOFTWARE FROM A COPYRIGHT PERSPECTIVE IN INDONESIA",
        date: "06 February, 2025",
        image: "/images/news2.jpg",
        description:
          "How is open source regulated in copyright law in Indonesia? Despite its nature...",
        fullText:
          "Full article content goes here. This is the detailed explanation...",
      },
      {
        id: 6,
        title:
          "PROTECTION OF OPEN-SOURCE SOFTWARE FROM A COPYRIGHT PERSPECTIVE IN INDONESIA",
        date: "06 February, 2025",
        image: "/images/news3.jpg",
        description:
          "How is open source regulated in copyright law in Indonesia? Despite its nature...",
        fullText:
          "Full article content goes here. This is the detailed explanation...",
      },
  ];

const AllNews = () => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedArticle, setSelectedArticle] = useState(null);

  useEffect(() => {
    const savedPosition = sessionStorage.getItem("scrollPosition");
    if (savedPosition) {
      window.scrollTo(0, savedPosition);
    }

    return () => {
      sessionStorage.setItem("scrollPosition", window.scrollY);
    };
  }, []);

  const openModal = (article) => {
    setSelectedArticle(article);
    setIsModalOpen(true);
  };

  const closeModal = () => {
    setIsModalOpen(false);
    setSelectedArticle(null);
  };

  return (
    <div className="AllNews">
      <div className="back-button-container">
        <Link to="/news" className="back-button">
          ← Back to News
        </Link>
      </div>

      <h2>All News</h2>
      <div className="news-container">
        {articles.map((article) => (
          <NewsCard
            key={article.id}
            article={article}
            onReadMoreClick={openModal}  // Pass the openModal function here
          />
        ))}
      </div>

      {isModalOpen && selectedArticle && (
        <ReadMore selectedArticle={selectedArticle} closeModal={closeModal} />
      )}
    </div>
  );
};

export default AllNews;
